function r301(loc){return new Response(null,{status:301,headers:{'Location':loc,'Cache-Control':'public, max-age=86400'}});}
function gone(){return new Response('Gone',{status:410,headers:{'Cache-Control':'public, max-age=86400'}});}

export default {
  async fetch(request){
    const url = new URL(request.url);
    // crawl-bloat feeds are not real pages -> tell Google they're gone
    if (url.pathname.endsWith('.atom')) return gone();
    const seg = url.pathname.split('/').filter(Boolean);
    // /products/<handle>  ->  exact marketplace product if we know it, else marketplace
    if (seg[0] === 'products' && seg[1]) {
      const dest = MAP[decodeURIComponent(seg[1]).toLowerCase()];
      return r301(dest || MARKET);
    }
    // /collections/* (category/faceted) -> marketplace browse (safe default)
    if (seg[0] === 'collections') return r301(MARKET);
    // homepage + anything else -> marketplace
    return r301(MARKET);
  }
};
